// MVP Profile Scorer
const items = $input.all();
const qualifiedLeads = [];

for (const item of items) {
  const data = item.json;

  // Profile Scraper uses 'followersCount' directly at the root level
  const followers = data.followersCount || 0;
  const username = data.username || "unknown";
  const bio = data.biography || "";

  // LET'S BE LENIENT FOR THE TEST: Score everyone 85
  let score = 85; 

  qualifiedLeads.push({
    json: {
      username: username,
      fullName: data.fullName || "",
      bio: bio,
      followers: followers,
      leadScore: score,
      status: "qualified",
      dateAdded: new Date().toISOString()
    }
  });
}

return qualifiedLeads;

// Random delay between 45-90 seconds to avoid patterns
const minDelay = 45000;
const maxDelay = 90000;
const randomDelay = Math.floor(Math.random() * (maxDelay - minDelay + 1) + minDelay);

return new Promise(resolve => {
  setTimeout(() => {
    resolve($input.all());
  }, randomDelay);
});

// Generate Daily Report
const today = new Date().toISOString().split('T')[0];
const yesterday = new Date(Date.now() - 24 * 60 * 60 * 1000).toISOString().split('T')[0];
const leads = $input.all().map(item => item.json);

// Calculate metrics
const newLeadsToday = leads.filter(l => l.dateAdded?.startsWith(today)).length;
const dmsSentToday = leads.filter(l => l.dmDate?.startsWith(today)).length;
const followUpsToday = leads.filter(l => l.lastFollowUpDate?.startsWith(today)).length;
const totalReplies = leads.filter(l => l.replied === true || l.replied === 'true').length;
const repliesToday = leads.filter(l => l.replyDate?.startsWith(today)).length;
const conversions = leads.filter(l => l.converted === true || l.converted === 'true').length;

const totalDms = leads.filter(l => l.status === 'dm_sent' || l.dmDate).length;
const conversionRate = totalDms > 0 ? ((conversions / totalDms) * 100).toFixed(2) : 0;
const replyRate = totalDms > 0 ? ((totalReplies / totalDms) * 100).toFixed(2) : 0;

// Top leads by score
const topLeads = leads
  .filter(l => l.leadScore > 80)
  .sort((a, b) => b.leadScore - a.leadScore)
  .slice(0, 5)
  .map(l => `@${l.username} (Score: ${l.leadScore})`);

const report = {
  date: today,
  summary: {
    newLeadsScraped: newLeadsToday,
    dmsSentToday: dmsSentToday,
    followUpsSent: followUpsToday,
    newReplies: repliesToday,
    totalConversions: conversions,
    replyRate: `${replyRate}%`,
    conversionRate: `${conversionRate}%`
  },
  pipeline: {
    totalLeads: leads.length,
    qualified: leads.filter(l => l.status === 'qualified' || l.leadScore >= 60).length,
    contacted: leads.filter(l => l.status === 'dm_sent' || l.dmDate).length,
    responded: totalReplies,
    converted: conversions
  },
  topOpportunities: topLeads,
  message: `📊 Daily Prospecting Report - ${today}

🎯 ACTIVITY TODAY:
• New leads scraped: ${newLeadsToday}
• DMs sent: ${dmsSentToday}
• Follow-ups: ${followUpsToday}
• New replies: ${repliesToday}

📈 CONVERSION METRICS:
• Reply rate: ${replyRate}%
• Conversion rate: ${conversionRate}%
• Total pipeline: ${leads.length} leads

🔥 TOP OPPORTUNITIES:
${topLeads.join('\n') || 'None yet'}

View full dashboard: https://docs.google.com/spreadsheets/d/YOUR_SHEET_ID`
};

return [{json: report}];

// Real-time dashboard stats
const leads = $input.all().map(item => item.json);
const today = new Date().toISOString().split('T')[0];

const stats = {
  totalLeads: leads.length,
  todayLeads: leads.filter(l => l.dateAdded?.startsWith(today)).length,
  dmsSent: leads.filter(l => l.dmDate).length,
  todayDms: leads.filter(l => l.dmDate?.startsWith(today)).length,
  replies: leads.filter(l => l.replied === true || l.replied === 'true').length,
  conversions: leads.filter(l => l.converted === true || l.converted === 'true').length,
  avgLeadScore: leads.length > 0 ? (leads.reduce((sum, l) => sum + (parseInt(l.leadScore) || 0), 0) / leads.length).toFixed(1) : 0,
  topLeads: leads
    .filter(l => (l.leadScore || 0) > 75)
    .sort((a, b) => (b.leadScore || 0) - (a.leadScore || 0))
    .slice(0, 10)
    .map(l => ({
      username: l.username,
      score: l.leadScore,
      followers: l.followers,
      status: l.status
    }))
};

const replyRate = stats.dmsSent > 0 ? ((stats.replies / stats.dmsSent) * 100).toFixed(1) : 0;
const conversionRate = stats.dmsSent > 0 ? ((stats.conversions / stats.dmsSent) * 100).toFixed(1) : 0;

const html = `<!DOCTYPE html>
<html>
<head>
    <meta charset="UTF-8">
    <meta http-equiv="refresh" content="30">
    <title>AI Agency Prospecting Dashboard</title>
    <style>
        * { margin: 0; padding: 0; box-sizing: border-box; }
        body { 
            font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, sans-serif; 
            background: linear-gradient(135deg, #0f172a 0%, #1e293b 100%);
            color: #e2e8f0;
            min-height: 100vh;
            padding: 40px 20px;
        }
        .container { max-width: 1200px; margin: 0 auto; }
        h1 { 
            font-size: 2.5rem; 
            margin-bottom: 8px; 
            background: linear-gradient(90deg, #3b82f6, #8b5cf6);
            -webkit-background-clip: text;
            -webkit-text-fill-color: transparent;
        }
        .subtitle { color: #64748b; margin-bottom: 32px; }
        .stats-grid { 
            display: grid; 
            grid-template-columns: repeat(auto-fit, minmax(250px, 1fr)); 
            gap: 20px; 
            margin-bottom: 32px;
        }
        .stat-card { 
            background: rgba(30, 41, 59, 0.8); 
            backdrop-filter: blur(10px);
            border: 1px solid rgba(255,255,255,0.1);
            border-radius: 16px; 
            padding: 24px;
            transition: transform 0.2s, box-shadow 0.2s;
        }
        .stat-card:hover { 
            transform: translateY(-4px); 
            box-shadow: 0 20px 40px rgba(0,0,0,0.3);
        }
        .stat-label { 
            font-size: 0.875rem; 
            color: #94a3b8; 
            text-transform: uppercase;
            letter-spacing: 0.05em;
            margin-bottom: 8px;
        }
        .stat-value { 
            font-size: 2.5rem; 
            font-weight: 700;
            margin-bottom: 4px;
        }
        .stat-change { 
            font-size: 0.875rem; 
            color: #22c55e;
        }
        .blue { color: #3b82f6; }
        .green { color: #22c55e; }
        .purple { color: #a855f7; }
        .orange { color: #f97316; }
        .pink { color: #ec4899; }
        .yellow { color: #eab308; }

        .section { 
            background: rgba(30, 41, 59, 0.6); 
            border-radius: 16px; 
            padding: 24px;
            margin-bottom: 24px;
            border: 1px solid rgba(255,255,255,0.05);
        }
        .section h2 { 
            font-size: 1.25rem; 
            margin-bottom: 16px;
            color: #f8fafc;
        }
        .lead-list { list-style: none; }
        .lead-item { 
            display: flex; 
            align-items: center; 
            justify-content: space-between;
            padding: 12px 0;
            border-bottom: 1px solid rgba(255,255,255,0.05);
        }
        .lead-item:last-child { border-bottom: none; }
        .lead-info { display: flex; align-items: center; gap: 12px; }
        .lead-avatar { 
            width: 40px; 
            height: 40px; 
            border-radius: 50%; 
            background: linear-gradient(135deg, #3b82f6, #8b5cf6);
            display: flex;
            align-items: center;
            justify-content: center;
            font-weight: 600;
            font-size: 0.875rem;
        }
        .lead-name { font-weight: 600; color: #f8fafc; }
        .lead-meta { font-size: 0.875rem; color: #64748b; }
        .score-badge { 
            background: rgba(59, 130, 246, 0.2);
            color: #3b82f6;
            padding: 4px 12px;
            border-radius: 20px;
            font-size: 0.875rem;
            font-weight: 600;
        }
        .status-badge {
            padding: 4px 12px;
            border-radius: 20px;
            font-size: 0.75rem;
            font-weight: 600;
            text-transform: uppercase;
        }
        .status-qualified { background: rgba(34, 197, 94, 0.2); color: #22c55e; }
        .status-dm_sent { background: rgba(168, 85, 247, 0.2); color: #a855f7; }
        .status-replied { background: rgba(236, 72, 153, 0.2); color: #ec4899; }

        .progress-bar {
            width: 100%;
            height: 8px;
            background: rgba(255,255,255,0.1);
            border-radius: 4px;
            overflow: hidden;
            margin-top: 8px;
        }
        .progress-fill {
            height: 100%;
            background: linear-gradient(90deg, #3b82f6, #8b5cf6);
            border-radius: 4px;
            transition: width 0.3s;
