        .live-indicator {
            display: inline-flex;
            align-items: center;
            gap: 8px;
            color: #22c55e;
            font-size: 0.875rem;
        }
        .pulse {
            width: 8px;
            height: 8px;
            background: #22c55e;
            border-radius: 50%;
            animation: pulse 2s infinite;
        }
        @keyframes pulse {
            0%, 100% { opacity: 1; }
            50% { opacity: 0.5; }
        }
    </style>
</head>
<body>
    <div class="container">
        <div style="display: flex; justify-content: space-between; align-items: center; margin-bottom: 32px;">
            <div>
                <h1>🤖 AI Agency Prospecting</h1>
                <p class="subtitle">Real-time Automation Dashboard</p>
            </div>
            <div class="live-indicator">
                <div class="pulse"></div>
                <span>Live • Auto-refresh: 30s</span>
            </div>
        </div>

        <div class="stats-grid">
            <div class="stat-card">
                <div class="stat-label">Total Leads</div>
                <div class="stat-value blue">${stats.totalLeads}</div>
                <div class="stat-change">+${stats.todayLeads} today</div>
            </div>
            <div class="stat-card">
                <div class="stat-label">DMs Sent</div>
                <div class="stat-value purple">${stats.dmsSent}</div>
                <div class="stat-change">+${stats.todayDms} today</div>
            </div>
            <div class="stat-card">
                <div class="stat-label">Reply Rate</div>
                <div class="stat-value green">${replyRate}%</div>
                <div class="progress-bar">
                    <div class="progress-fill" style="width: ${replyRate}%"></div>
                </div>
            </div>
            <div class="stat-card">
                <div class="stat-label">Conversion Rate</div>
                <div class="stat-value pink">${conversionRate}%</div>
                <div class="stat-change">${stats.conversions} converted</div>
            </div>
            <div class="stat-card">
                <div class="stat-label">Avg Lead Score</div>
                <div class="stat-value yellow">${stats.avgLeadScore}</div>
                <div class="stat-change">Out of 100</div>
            </div>
            <div class="stat-card">
                <div class="stat-label">Active Replies</div>
                <div class="stat-value orange">${stats.replies}</div>
                <div class="stat-change">Conversations</div>
            </div>
        </div>

        <div class="section">
            <h2>🔥 Top Opportunities</h2>
            <ul class="lead-list">
                ${stats.topLeads.map(lead => \`
                    <li class="lead-item">
                        <div class="lead-info">
                            <div class="lead-avatar">\${lead.username.substring(0,2).toUpperCase()}</div>
                            <div>
                                <div class="lead-name">@\${lead.username}</div>
                                <div class="lead-meta">\${lead.followers?.toLocaleString() || 'N/A'} followers</div>
                            </div>
                        </div>
                        <div style="display: flex; gap: 12px; align-items: center;">
                            <span class="score-badge">\${lead.score}</span>
